// ─────────────────────────────────────────────
// VHSYS :: regular_bills
// Rota   : POST /regular_bills  
// Fase 6 : Regular Bills
// ─────────────────────────────────────────────
// Input  : Array de objetos com dados estruturados
// Output : { message: 'GET A NEW regular_bills status' } HTTP 201
// Banco  : UPSERT DespesasRecorrentes
// Chave  : id_custo
// ─────────────────────────────────────────────

const input = $input.first().json;
const body = input.body || input;

// Validar input
if (!Array.isArray(body)) {
  return {
    statusCode: 400,
    body: { error: 'Expected array of regular bills' }
  };
}

if (body.length === 0) {
  return {
    statusCode: 400,
    body: { error: 'Empty array provided' }
  };
}

// Log inicial
console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'input_received',
  items_count: body.length,
  level: 'info'
}));

// Transformar todos os itens
const processedBills = body.map((item, index) => {
  if (!item.id_custo) {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      route: 'regular_bills',
      event: 'item_skipped_missing_id',
      item_index: index,
      level: 'warn'
    }));
    return null;
  }

  return {
    id_custo: String(item.id_custo),
    id_empresa: String(item.id_empresa || '1'),
    nome_conta: String(item.nome_conta || ''),
    id_categoria: String(item.id_categoria || '1'),
    categoria_custo: String(item.categoria_custo || ''),
    id_banco: String(item.id_banco || '1'),
    id_fornecedor: String(item.id_fornecedor || '1'),
    nome_fornecedor: String(item.nome_fornecedor || ''),
    vencimento_custo: String(item.vencimento_custo || ''),
    valor_custo: String(item.valor_custo || '0'),
    observacoes_custo: String(item.observacoes_custo || ''),
    id_centro_custos: String(item.id_centro_custos || '1'),
    status_custo: String(item.status_custo || 'ATIVO'),
    forma_pagamento: String(item.forma_pagamento || 'DINHEIRO'),
    periodicidade: String(item.periodicidade || 'MENSAL'),
    dia_semana_ocorrencia: String(item.dia_semana_ocorrencia || ''),
    dia_mes_ocorrencia: String(item.dia_mes_ocorrencia || ''),
    intervalo_dias_ocorrencia: String(item.intervalo_dias_ocorrencia || ''),
    data_inicio_ocorrencia: item.data_inicio_ocorrencia || null,
    data_fim_ocorrencia: item.data_fim_ocorrencia || null,
    data_cad_custo: item.data_cad_custo || (new Date()).toISOString().split('T')[0],
    lixeira: String(item.lixeira || 'NAO')
  };
}).filter(item => item !== null);

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'input_processed',
  valid_items: processedBills.length,
  total_items: body.length,
  level: 'info'
}));

return { processedBills };

// ─────────────────────────────────────────────
// VHSYS :: regular_bills - Success Response
// ─────────────────────────────────────────────
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'bulk_upsert_success',
  level: 'info'
}));

return {
  statusCode: 201,
  body: { 
    message: 'GET A NEW regular_bills status'
  }
};

// ─────────────────────────────────────────────
// VHSYS :: regular_bills - Error Response
// ─────────────────────────────────────────────
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { error: errData.message || 'Database error' }
};
